Implement the bookmark/unbookmark functionality in the event details page and create a bookmarks listing view. Use the existing bookmarks table in the database.

Pseudocode:
```
// Bookmark toggle component
function BookmarkButton({ eventId }) {
  const [isBookmarked, setIsBookmarked] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check if event is bookmarked
    checkBookmarkStatus();
  }, [eventId]);

  async function toggleBookmark() {
    setLoading(true);
    try {
      if (isBookmarked) {
        // Remove bookmark
        await supabase.from('bookmarks').delete().eq('event_id', eventId);
      } else {
        // Add bookmark
        await supabase.from('bookmarks').insert({ event_id: eventId });
      }
      setIsBookmarked(!isBookmarked);
    } catch (error) {
      // Handle error
    } finally {
      setLoading(false);
    }
  }

  return (
    <Button
      onClick={toggleBookmark}
      disabled={loading}
    >
      {isBookmarked ? <BookmarkFilled /> : <BookmarkOutline />}
      {isBookmarked ? t('removeBookmark') : t('addBookmark')}
    </Button>
  );
}

